def _case_creator_license_contract(
    engine: RoyaltyDrivenLLM,
    *,
    signing_secret: str | None,
) -> dict[str, Any]:
    return make_creator_license_contract(
        creators=engine.creators,
        works=engine.works,
        issuer="rdllm-certifier",
        provider="provider:rdllm-certifier",
        effective_at=CERTIFICATION_ISSUED_AT,
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )


