class CaseBuilder:
    """Small helper that records named checks without hiding failures."""

    def __init__(self, case_id: str, title: str) -> None:
        self.case_id = case_id
        self.title = title
        self.checks: dict[str, Any] = {}
        self.artifacts: dict[str, Any] = {}
        self.errors: list[str] = []

    def check(self, name: str, condition: bool, detail: Any | None = None) -> None:
        self.checks[name] = bool(condition) if detail is None else detail
        if not condition:
            self.errors.append(name)

    def error_if(self, errors: list[str], prefix: str) -> None:
        self.checks[prefix] = errors
        for error in errors:
            self.errors.append(f"{prefix}: {error}")

    def artifact(self, name: str, value: Any) -> None:
        self.artifacts[name] = value

    def report(self) -> dict[str, Any]:
        return {
            "id": self.case_id,
            "title": self.title,
            "status": "passed" if not self.errors else "failed",
            "checks": self.checks,
            "artifacts": self.artifacts,
            "errors": self.errors,
        }


def _creator_pool_total(event: UsageEvent) -> Decimal:
    return sum((share.payout for share in event.royalty_shares), Decimal("0"))


def _span_prefixes_from_claims(event: UsageEvent) -> list[str]:
    return [
        claim.evidence_span_hash[:12]
        for claim in event.claim_support
        if claim.supported and claim.evidence_span_hash
    ]


def _grounded_generation_case(engine: RoyaltyDrivenLLM) -> dict[str, Any]:
    case = CaseBuilder(
        "grounded_generation",
        "Generated answer carries sources, claim support, evidence spans, and balanced payouts.",
    )
    event = engine.generate(
        "How should AI prove attribution?",
        gross_revenue=Decimal("1.00"),
    )
    case.error_if(engine.audit_event(event), "event_audit_errors")
    case.check("creator_pool_balanced", _creator_pool_total(event) == event.creator_pool)
    case.check("has_visible_sources", bool(event.source_references))
    case.check("footer_source_labels_match_sources", source_labels_in_output(event.output) == [source.label for source in event.source_references])
    case.check("all_claims_supported", bool(event.claim_support) and all(claim.supported for claim in event.claim_support))
    case.check("span_hashes_in_footer", all(prefix in span_hash_prefixes_in_output(event.output) for prefix in _span_prefixes_from_claims(event)))
    case.check("policy_allowed", event.grounding_report.get("policy_status") == "allowed")
    case.check("grounding_quality_verified", event.grounding_quality.get("verdict") == "verified")
    case.artifact("event_id", event.event_id)
    case.artifact("event_hash", event.event_hash)
    case.artifact("source_count", len(event.source_references))
    case.artifact("claim_count", len(event.claim_support))
    return case.report()


def _external_text_attribution_case(engine: RoyaltyDrivenLLM) -> dict[str, Any]:
    case = CaseBuilder(
        "external_text_attribution",
        "Externally generated text is matched back to registered owners and grounded in a source footer.",
    )
    event = engine.attribute_text(
        "External AI output submitted for owner attribution",
        TEXT_ATTRIBUTION_OUTPUT,
        gross_revenue=Decimal("1.00"),
    )
    payouts = engine.aggregate_creator_payouts(event)
    top_match_score = event.royalty_shares[0].text_match_score if event.royalty_shares else 0.0
    case.error_if(engine.audit_event(event), "event_audit_errors")
    case.check("arjun_paid", payouts.get("arjun", Decimal("0")) > Decimal("0"))
    case.check("text_match_score_positive", top_match_score > 0.0)
    case.check("source_footer_present", "Sources" in event.output and "[S1]" in event.output)
    case.check("claim_evidence_present", "Claim Evidence" in event.output)
    case.check("span_hashes_in_footer", all(prefix in span_hash_prefixes_in_output(event.output) for prefix in _span_prefixes_from_claims(event)))
    case.check("grounded", event.grounding_report.get("status") == "grounded")
    case.check("grounding_quality_verified", event.grounding_quality.get("verdict") == "verified")
    case.artifact("event_id", event.event_id)
    case.artifact("top_text_match_score", round(top_match_score, 8))
    case.artifact("creator_payouts", {creator_id: str(payout) for creator_id, payout in payouts.items()})
    return case.report()


def _unattributed_escrow_case(engine: RoyaltyDrivenLLM) -> dict[str, Any]:
    case = CaseBuilder(
        "unattributed_escrow",
        "Unmatched text is assigned to unattributed escrow instead of a false owner.",
    )
    event = engine.attribute_text(
        "zzzz",
        "qwerty asdfgh",
        gross_revenue=Decimal("1.00"),
    )
    share = event.royalty_shares[0] if event.royalty_shares else None
    case.error_if(engine.audit_event(event), "event_audit_errors")
    case.check("unattributed_escrow_share", bool(share and share.creator_id == "unattributed_escrow"))
    case.check("escrow_gets_full_creator_pool", bool(share and share.payout == event.creator_pool))
    case.check("no_registered_source_footer", "[U1] No registered source matched" in event.output)
    case.check("no_visible_sources", not event.source_references)
    case.artifact("event_id", event.event_id)
    case.artifact("creator_pool", str(event.creator_pool))
    return case.report()


def _rights_blocked_generation_case(
    restricted_corpus_path: str | Path,
    *,
    signing_secret: str | None,
    jurisdiction: str,
    creator_pool_rate: Decimal,
    top_k: int,
) -> dict[str, Any]:
    case = CaseBuilder(
        "rights_blocked_generation",
        "Restricted source matches are blocked by policy and assigned to rights-conflict escrow.",
    )
    engine = RoyaltyDrivenLLM.from_corpus_file(
        restricted_corpus_path,
        creator_pool_rate=creator_pool_rate,
        top_k=top_k,
        jurisdiction=jurisdiction,
    )
    event = engine.generate(
        "What does reserved source text say about retrieval and generation?",
        gross_revenue=Decimal("1.00"),
    )
    receipt = make_attribution_receipt(
        event,
        issuer="rdllm-certifier",
        model_id="rdllm-reference",
        model_version=CERTIFICATION_VERSION,
        route_id="cert:rights",
        issued_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    conformance = verify_conformance_bundle(
        event=event,
        receipt=receipt,
        signing_secret=signing_secret,
    )
    share = event.royalty_shares[0] if event.royalty_shares else None
    case.error_if(engine.audit_event(event), "event_audit_errors")
    case.error_if(conformance["errors"], "conformance_errors")
    case.check("policy_blocked", event.grounding_report.get("policy_status") == "blocked")
    case.check("rights_blocked_status", event.grounding_report.get("status") == "rights_blocked")
    case.check("rights_conflict_escrow_share", bool(share and share.creator_id == "rights_conflict_escrow"))
    case.check("escrow_gets_full_creator_pool", bool(share and share.payout == event.creator_pool))
    case.check("no_visible_sources_when_blocked", not event.source_references)
    case.check("rights_footer_present", "[R1]" in event.output and "Rights:" in event.output)
    case.artifact("event_id", event.event_id)
    case.artifact("receipt_hash", receipt["receipt_hash"])
    return case.report()


def _receipt_transparency_case(
    engine: RoyaltyDrivenLLM,
    *,
    signing_secret: str | None,
) -> dict[str, Any]:
    case = CaseBuilder(
        "receipt_transparency_conformance",
        "Receipt, public receipt, transparency log, and conformance proof agree.",
    )
    event = engine.generate(
        "How should any AI system prove creator attribution for an answer?",
        gross_revenue=Decimal("1.00"),
    )
    receipt = make_attribution_receipt(
        event,
        issuer="rdllm-certifier",
        model_id="rdllm-reference",
        model_version=CERTIFICATION_VERSION,
        route_id="cert:receipt",
        issued_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    log = TransparencyLog()
    entry = log.append(receipt)
    proof = log.proof_for(receipt["receipt_hash"])
    conformance = verify_conformance_bundle(
        event=event,
        receipt=receipt,
        signing_secret=signing_secret,
        transparency_log=log,
        proof=proof,
    )
    public = public_receipt(receipt)
    case.error_if(engine.audit_event(event), "event_audit_errors")
    case.error_if(verify_receipt(receipt, signing_secret=signing_secret), "receipt_errors")
    case.error_if(conformance["errors"], "conformance_errors")
    case.check("conformance_ok", conformance["status"] == "ok")
    case.check("proof_verified", conformance["checks"]["proof_verified"] is True)
    case.check("log_root_present", bool(conformance["checks"]["log_root"]))
    case.check("public_receipt_privacy_reduced", "economics" not in public and "grounding" not in public)
    case.artifact("event_id", event.event_id)
    case.artifact("receipt_hash", receipt["receipt_hash"])
    case.artifact("transparency_entry", entry)
    case.artifact("transparency_root", log.root())
    return case.report()


def _tamper_detection_case(
    engine: RoyaltyDrivenLLM,
    *,
    signing_secret: str | None,
) -> dict[str, Any]:
    case = CaseBuilder(
        "tamper_detection",
        "Verifier rejects missing evidence-span hashes and modified receipt payloads.",
    )
    event = engine.generate(
        "How should AI prove attribution?",
        gross_revenue=Decimal("1.00"),
    )
    receipt = make_attribution_receipt(
        event,
        issuer="rdllm-certifier",
        model_id="rdllm-reference",
        model_version=CERTIFICATION_VERSION,
        route_id="cert:tamper",
        issued_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    tampered_event = UsageEvent.from_dict(event.to_dict())
    tampered_event.output = tampered_event.output.replace("span=", "span_removed=", 1)
    footer_errors = verify_event_receipt(
        tampered_event,
        receipt,
        signing_secret=signing_secret,
    )
    tampered_receipt = deepcopy(receipt)
    tampered_receipt["payload"]["economics"]["creator_pool"] = "0.000000"
    receipt_errors = verify_receipt(tampered_receipt, signing_secret=signing_secret)
    case.check(
        "missing_span_detected",
        any("rendered output missing evidence span hash" in error for error in footer_errors),
        footer_errors,
    )
    case.check(
        "receipt_payload_tamper_detected",
        any(
            error in {"receipt hash is not reproducible", "receipt signature is invalid"}
            for error in receipt_errors
        ),
        receipt_errors,
    )
    case.artifact("event_id", event.event_id)
    case.artifact("receipt_hash", receipt["receipt_hash"])
    return case.report()


def _rights_manifest_case(engine: RoyaltyDrivenLLM) -> dict[str, Any]:
    case = CaseBuilder(
        "rights_manifest",
        "Corpus exports a machine-readable rights manifest for policy interchange.",
    )
