def _assurance_bundle_case(
    engine: RoyaltyDrivenLLM,
    *,
    signing_secret: str | None,
) -> dict[str, Any]:
    case = CaseBuilder(
        "assurance_bundle_publication",
        "Assurance bundle publishes artifact hashes and inclusion proofs for independent verification.",
    )
    event = engine.generate(
        "How should AI prove attribution?",
        gross_revenue=Decimal("1.00"),
    )
    ledger = RoyaltyLedger()
    ledger.record(event)
    certification = _certification_stub("RDLLM-L17")
    certification["summary"]["case_count"] = 18
    certification["summary"]["passed"] = 18
    certification.pop("report_hash", None)
    certification["report_hash"] = hash_payload(certification)
    receipt = make_attribution_receipt(
        event,
        issuer="rdllm-certifier",
        issued_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    trace = make_trace_exchange(event, receipt=receipt)
    provider_card = make_provider_attribution_card(
        ledger.to_dict(),
        certification_report=certification,
        issuer="rdllm-certifier",
        provider="provider:reference",
        model_id="rdllm-reference-python",
        model_version="2026-05",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    training_summary = make_training_content_summary(
        engine,
        certification_report=certification,
        provider_card=provider_card,
        issuer="rdllm-certifier",
        provider="provider:reference",
        model_id="rdllm-reference-python",
        model_version="2026-05",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    artifacts = [
        ("certification", "certification_report", certification),
        ("ledger", "ledger", ledger.to_dict()),
        ("provider_card", "provider_attribution_card", provider_card),
        ("receipt", "attribution_receipt", receipt),
        ("trace", "trace_exchange", trace),
        ("training_summary", "training_content_summary", training_summary),
    ]
    bundle = make_assurance_bundle(
        artifacts,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    tampered = deepcopy(bundle)
    tampered["artifacts"] = deepcopy(tampered["artifacts"])
    tampered["artifacts"][0]["payload_hash"] = "0" * 64
    tampered_errors = verify_assurance_bundle(
        artifacts,
        tampered,
        signing_secret=signing_secret,
    )
    missing_proof = deepcopy(bundle)
    missing_proof["inclusion_proofs"] = dict(missing_proof["inclusion_proofs"])
    missing_proof["inclusion_proofs"].pop("provider_card", None)
    missing_proof_errors = verify_assurance_bundle(
        artifacts,
        missing_proof,
        signing_secret=signing_secret,
    )

    case.error_if(
        verify_assurance_bundle(
            artifacts,
            bundle,
            signing_secret=signing_secret,
        ),
        "assurance_bundle_errors",
    )
    case.check(
        "bundle_declares_publication_profile",
        all(bundle["publication_profile"].values()),
        bundle["publication_profile"],
    )
    case.check(
        "bundle_covers_required_artifacts",
        bundle["summary"]["artifact_count"] == len(artifacts)
        and {"certification_report", "provider_attribution_card", "training_content_summary"}.issubset(
            set(bundle["summary"]["artifact_types"])
        ),
        bundle["summary"],
    )
    case.check(
        "bundle_proofs_cover_every_artifact",
        set(bundle["inclusion_proofs"]) == {name for name, _artifact_type, _payload in artifacts},
        sorted(bundle["inclusion_proofs"]),
    )
    case.check(
        "bundle_discloses_no_payloads",
        bundle["privacy"]["artifact_payloads_disclosed"] is False
        and bundle["privacy"]["public_bundle_uses_hashes_and_inclusion_proofs"] is True,
        bundle["privacy"],
    )
    case.check(
        "artifact_hash_tampering_rejected",
        any("artifacts does not match" in error for error in tampered_errors),
        tampered_errors,
    )
    case.check(
        "missing_inclusion_proof_rejected",
        any("inclusion_proofs does not match" in error for error in missing_proof_errors)
        or any("missing assurance inclusion proof" in error for error in missing_proof_errors),
        missing_proof_errors,
    )
    case.artifact("bundle_hash", bundle["bundle_hash"])
    case.artifact("artifact_count", bundle["summary"]["artifact_count"])
    case.artifact("root", bundle["summary"]["root"])
    return case.report()


def _answer_provenance_card_case(
    engine: RoyaltyDrivenLLM,
    *,
    signing_secret: str | None,
) -> dict[str, Any]:
    case = CaseBuilder(
        "answer_provenance_card",
        "Answer provenance card binds visible source footer, claim spans, receipt, trace, and attribution-suppression checks for user verification.",
    )
    event = engine.generate(
        "How should AI prove attribution?",
        gross_revenue=Decimal("1.00"),
    )
    receipt = make_attribution_receipt(
        event,
        issuer="rdllm-certifier",
        issued_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    trace = make_trace_exchange(event, receipt=receipt)
    card = make_answer_provenance_card(
        event,
        receipt=receipt,
        trace=trace,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )

    tampered_card = deepcopy(card)
    tampered_card["sources"] = deepcopy(tampered_card["sources"])
    tampered_card["sources"][0]["content_hash"] = "0" * 64
    tampered_errors = verify_answer_provenance_card(
        event,
        tampered_card,
        receipt=receipt,
        trace=trace,
        signing_secret=signing_secret,
    )

    tampered_footer = UsageEvent.from_dict(event.to_dict())
    tampered_footer.output = tampered_footer.output.replace("[S1]", "[S9]", 1)
    footer_errors = verify_answer_provenance_card(
        tampered_footer,
        card,
        receipt=receipt,
        trace=trace,
        signing_secret=signing_secret,
    )

    card_json = canonical_json(card)
    private_text_absent = (
        event.prompt not in card_json
        and event.answer_text not in card_json
        and all(source.quote not in card_json for source in event.source_references)
        and all(claim.evidence_text not in card_json for claim in event.claim_support)
    )

    case.error_if(
        verify_answer_provenance_card(
            event,
            card,
            receipt=receipt,
            trace=trace,
            signing_secret=signing_secret,
        ),
        "answer_provenance_card_errors",
    )
    case.check(
        "card_binds_receipt_and_trace",
        card["event"]["receipt_hash"] == receipt["receipt_hash"]
        and card["event"]["trace_hash"] == trace["trace_hash"],
        card["event"],
    )
    case.check(
        "card_binds_visible_footer",
        card["footer_checks"]["source_labels_match"]
        and card["footer_checks"]["claim_span_prefixes_match"]
        and card["verification"]["public_user_can_verify_footer"],
        card["footer_checks"],
    )
    case.check(
        "card_detects_no_attribution_suppression",
        card["footer_checks"]["attribution_suppression_detected"] is False
        and card["footer_checks"]["attribution_suppression_count"] == 0
        and not card["footer_checks"]["omitted_source_labels"],
        card["footer_checks"],
    )
    case.check(
        "card_reports_grounding_state",
        card["grounding"]["quality_verdict"] == "verified"
        and card["grounding"]["attribution_gap_verdict"] == "closed"
        and card["grounding"]["supported_claim_count"] > 0,
        card["grounding"],
    )
    case.check("card_discloses_no_private_text", private_text_absent)
    case.check(
        "card_tampering_rejected",
        any("sources does not match" in error for error in tampered_errors)
        or any("hash is not reproducible" in error for error in tampered_errors),
        tampered_errors,
    )
    case.check(
        "footer_tampering_rejected",
        any("does not match event" in error for error in footer_errors)
        or any("receipt:" in error for error in footer_errors),
        footer_errors,
    )
    case.artifact("card_hash", card["card_hash"])
    case.artifact("receipt_hash", receipt["receipt_hash"])
    case.artifact("trace_hash", trace["trace_hash"])
    case.artifact("source_count", card["grounding"]["source_count"])
    case.artifact("claim_count", card["grounding"]["claim_count"])
    return case.report()


def _source_materialization_case(
    engine: RoyaltyDrivenLLM,
    *,
    signing_secret: str | None,
) -> dict[str, Any]:
    case = CaseBuilder(
        "source_materialization_verification",
        "Source verification report materializes cited sources and claim evidence from registered content.",
    )
    event = engine.generate(
        "How should AI prove attribution?",
        gross_revenue=Decimal("1.00"),
    )
    receipt = make_attribution_receipt(
        event,
        issuer="rdllm-certifier",
        issued_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    trace = make_trace_exchange(event, receipt=receipt)
    card = make_answer_provenance_card(
        event,
        receipt=receipt,
        trace=trace,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    report = make_source_verification_report(
        event,
        engine,
        answer_card=card,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )

    tampered_report = deepcopy(report)
    tampered_report["sources"] = deepcopy(tampered_report["sources"])
    tampered_report["sources"][0]["content_hash_matches_registry"] = False
    tampered_report_errors = verify_source_verification_report(
        event,
        engine,
        tampered_report,
        answer_card=card,
        signing_secret=signing_secret,
    )

    tampered_event_data = event.to_dict()
    tampered_event_data["source_references"][0]["content_hash"] = "0" * 64
    tampered_event = UsageEvent.from_dict(tampered_event_data)
    tampered_event_errors = verify_source_verification_report(
        tampered_event,
        engine,
        report,
        answer_card=card,
        signing_secret=signing_secret,
    )

    stale_card = deepcopy(card)
    stale_card["event"] = dict(stale_card["event"])
    stale_card["event"]["event_hash"] = "0" * 64
    stale_card_errors = verify_source_verification_report(
        event,
        engine,
        report,
        answer_card=stale_card,
        signing_secret=signing_secret,
    )

    report_json = canonical_json(report)
    private_text_absent = (
        event.prompt not in report_json
        and event.answer_text not in report_json
        and all(source.quote not in report_json for source in event.source_references)
        and all(claim.claim not in report_json for claim in event.claim_support)
        and all(claim.evidence_text not in report_json for claim in event.claim_support)
    )

    case.error_if(
        verify_source_verification_report(
            event,
            engine,
            report,
            answer_card=card,
            signing_secret=signing_secret,
        ),
        "source_verification_report_errors",
    )
    case.check(
        "all_sources_and_supported_claims_materialized",
        report["summary"]["status"] == "verified"
        and report["summary"]["all_sources_materialized"]
        and report["summary"]["all_supported_claims_materialized"]
        and report["summary"]["materialized_source_count"] == report["summary"]["source_count"]
        and report["summary"]["materialized_supported_claim_count"]
        == report["summary"]["supported_claim_count"],
        report["summary"],
    )
    case.check(
        "answer_card_binding_materialized",
        report["answer_card"]["answer_card_hash"] == card["card_hash"]
        and report["answer_card"]["answer_card_bound"]
        and report["summary"]["answer_card_bound"],
        report["answer_card"],
    )
    case.check(
        "registered_content_hashes_recomputed",
        all(source["content_hash_reproducible"] for source in report["sources"])
        and all(
            claim["evidence_hash_reproducible"]
            for claim in report["claims"]
            if claim["supported"]
        ),
        {
            "sources": report["sources"],
            "claims": report["claims"],
        },
    )
    case.check("source_report_discloses_no_private_text", private_text_absent)
    case.check(
        "source_report_tampering_rejected",
        any("hash is not reproducible" in error for error in tampered_report_errors)
        or any("sources does not match" in error for error in tampered_report_errors),
        tampered_report_errors,
    )
    case.check(
        "source_event_tampering_rejected",
        any("sources does not match" in error for error in tampered_event_errors)
        or any("status is not verified" in error for error in tampered_event_errors),
        tampered_event_errors,
    )
    case.check(
        "stale_answer_card_binding_rejected",
        any("answer_card does not match" in error for error in stale_card_errors)
        or any("status is not verified" in error for error in stale_card_errors),
        stale_card_errors,
    )
    case.artifact("report_hash", report["report_hash"])
    case.artifact("answer_card_hash", report["answer_card"]["answer_card_hash"])
    case.artifact("source_count", report["summary"]["source_count"])
    case.artifact("claim_count", report["summary"]["claim_count"])
    return case.report()


def _response_envelope_case(
    engine: RoyaltyDrivenLLM,
    *,
    signing_secret: str | None,
) -> dict[str, Any]:
    case = CaseBuilder(
        "response_envelope_public_verification",
        "Response envelope packages the rendered answer with public proof artifacts for API delivery.",
    )
    event = engine.generate(
        "How should AI prove attribution?",
        gross_revenue=Decimal("1.00"),
    )
    ledger = RoyaltyLedger()
    ledger.record(event)
    receipt = make_attribution_receipt(
        event,
        issuer="rdllm-certifier",
        issued_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    trace = make_trace_exchange(event, receipt=receipt)
    card = make_answer_provenance_card(
        event,
        receipt=receipt,
        trace=trace,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    source_report = make_source_verification_report(
        event,
        engine,
        answer_card=card,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    certification = {
        "certification_version": CERTIFICATION_VERSION,
        "suite": CERTIFICATION_SUITE,
        "issued_at": CERTIFICATION_ISSUED_AT,
        "summary": {
            "status": "passed",
            "case_count": 21,
            "passed": 21,
            "failed": 0,
            "score": 1.0,
            "highest_level": "RDLLM-L20",
        },
        "levels": {},
        "cases": [],
    }
    certification["report_hash"] = hash_payload(certification)
    provider_card = make_provider_attribution_card(
        ledger.to_dict(),
        certification_report=certification,
        issuer="rdllm-certifier",
        provider="provider:rdllm-reference",
        model_id="model:rdllm-certification",
        model_version="2026-05",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    envelope = make_response_envelope(
        event,
        answer_card=card,
        source_verification_report=source_report,
        public_receipt=public_receipt(receipt),
        provider_card=provider_card,
        certification_report=certification,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )

    tampered_output = deepcopy(envelope)
    tampered_output["response"] = dict(tampered_output["response"])
    tampered_output["response"]["rendered_output"] = tampered_output["response"][
        "rendered_output"
    ].replace("[S1]", "[S9]", 1)
    tampered_output_errors = verify_response_envelope(
        tampered_output,
        signing_secret=signing_secret,
    )

    tampered_artifact = deepcopy(envelope)
    tampered_artifact["embedded_artifacts"] = deepcopy(
        tampered_artifact["embedded_artifacts"]
    )
    tampered_artifact["embedded_artifacts"]["source_verification_report"][
        "summary"
    ] = dict(
        tampered_artifact["embedded_artifacts"]["source_verification_report"][
            "summary"
        ]
    )
    tampered_artifact["embedded_artifacts"]["source_verification_report"]["summary"][
        "status"
    ] = "failed"
    tampered_artifact_errors = verify_response_envelope(
        tampered_artifact,
        signing_secret=signing_secret,
    )

    envelope_json = canonical_json(envelope)
    full_source_text_absent = all(
        chunk.text not in envelope_json for chunk in engine.chunks
    )

    case.error_if(
        verify_response_envelope(envelope, signing_secret=signing_secret),
        "response_envelope_errors",
    )
    case.check(
        "envelope_public_verification_passes",
        envelope["summary"]["status"] == "verified"
        and all(envelope["verification"].values())
        and envelope["summary"]["artifact_count"] >= 5,
        envelope["verification"],
    )
    case.check(
        "envelope_binds_visible_output_to_artifacts",
        envelope["commitments"]["rendered_output_hash"]
        == card["event"]["rendered_output_hash"]
        == source_report["event"]["rendered_output_hash"]
        and envelope["commitments"]["answer_card_hash"] == card["card_hash"]
        and envelope["commitments"]["source_verification_report_hash"]
        == source_report["report_hash"],
        envelope["commitments"],
    )
    case.check(
        "envelope_carries_provider_and_certification_posture",
        envelope["embedded_artifacts"]["provider_attribution_card"]["card_hash"]
        == provider_card["card_hash"]
        and envelope["certification"]["highest_level"] == "RDLLM-L20"
        and envelope["verification"]["provider_discloses_response_surface"],
        envelope["certification"],
    )
    case.check(
        "envelope_redacts_private_inputs_and_corpus",
        full_source_text_absent
        and envelope["privacy"]["private_prompt_payload_disclosed"] is False
        and envelope["privacy"]["private_source_corpus_disclosed"] is False,
        envelope["privacy"],
    )
    case.check(
        "rendered_output_tampering_rejected",
        any("rendered output hash" in error for error in tampered_output_errors)
        or any("source labels" in error for error in tampered_output_errors),
        tampered_output_errors,
    )
    case.check(
        "embedded_artifact_tampering_rejected",
        any("embedded source_verification_report hash" in error for error in tampered_artifact_errors)
        or any("artifact index" in error for error in tampered_artifact_errors)
        or any("verification summary" in error for error in tampered_artifact_errors),
        tampered_artifact_errors,
    )
    case.artifact("envelope_hash", envelope["envelope_hash"])
    case.artifact("artifact_count", envelope["summary"]["artifact_count"])
    case.artifact("answer_card_hash", card["card_hash"])
    case.artifact("source_report_hash", source_report["report_hash"])
    return case.report()


def _integration_profile_case(
    engine: RoyaltyDrivenLLM,
    *,
    signing_secret: str | None,
) -> dict[str, Any]:
    case = CaseBuilder(
        "integration_profile_contract",
        "Integration profile publishes the API contract, schemas, verifier commands, and bound public proof hashes.",
    )
    event = engine.generate(
        "How should AI prove attribution?",
        gross_revenue=Decimal("1.00"),
    )
    ledger = RoyaltyLedger()
    ledger.record(event)
    receipt = make_attribution_receipt(
        event,
        issuer="rdllm-certifier",
        issued_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    trace = make_trace_exchange(event, receipt=receipt)
    card = make_answer_provenance_card(
        event,
        receipt=receipt,
        trace=trace,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    source_report = make_source_verification_report(
        event,
        engine,
        answer_card=card,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    certification = {
        "certification_version": CERTIFICATION_VERSION,
        "suite": CERTIFICATION_SUITE,
        "issued_at": CERTIFICATION_ISSUED_AT,
        "summary": {
            "status": "passed",
            "case_count": 22,
            "passed": 22,
            "failed": 0,
            "score": 1.0,
            "highest_level": "RDLLM-L21",
        },
        "levels": {},
        "cases": [],
    }
    certification["report_hash"] = hash_payload(certification)
    provider_card = make_provider_attribution_card(
        ledger.to_dict(),
        certification_report=certification,
        issuer="rdllm-certifier",
        provider="provider:rdllm-reference",
        model_id="model:rdllm-certification",
        model_version="2026-05",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    envelope = make_response_envelope(
        event,
        answer_card=card,
        source_verification_report=source_report,
        public_receipt=public_receipt(receipt),
        provider_card=provider_card,
        certification_report=certification,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    assurance = make_assurance_bundle(
        [
            ("certification", "certification_report", certification),
            ("response_envelope", "response_envelope", envelope),
            ("answer_card", "answer_provenance_card", card),
            ("source_verification", "source_verification_report", source_report),
            ("provider_card", "provider_attribution_card", provider_card),
            ("receipt", "attribution_receipt", receipt),
            ("trace", "trace_exchange", trace),
        ],
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    profile = make_integration_profile(
        provider_card=provider_card,
        certification_report=certification,
        response_envelope=envelope,
        assurance_bundle=assurance,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )

    tampered_profile = deepcopy(profile)
    tampered_profile["api_contract"] = deepcopy(tampered_profile["api_contract"])
    tampered_profile["api_contract"]["required_response_format"] = "text/plain"
    tampered_profile_errors = verify_integration_profile(
        tampered_profile,
        provider_card=provider_card,
        certification_report=certification,
        response_envelope=envelope,
        assurance_bundle=assurance,
        signing_secret=signing_secret,
    )

    lower_certification = deepcopy(certification)
    lower_certification["summary"] = dict(lower_certification["summary"])
    lower_certification["summary"]["highest_level"] = "RDLLM-L20"
    lower_certification.pop("report_hash")
    lower_certification["report_hash"] = hash_payload(lower_certification)
    lower_profile_errors = verify_integration_profile(
        profile,
        provider_card=provider_card,
        certification_report=lower_certification,
        response_envelope=envelope,
        assurance_bundle=assurance,
        signing_secret=signing_secret,
    )

    missing_surface_card = deepcopy(provider_card)
    missing_surface_card["public_disclosure_surfaces"] = dict(
        missing_surface_card["public_disclosure_surfaces"]
    )
    missing_surface_card["public_disclosure_surfaces"]["response_envelope"] = False
    missing_surface_errors = verify_integration_profile(
        profile,
        provider_card=missing_surface_card,
        certification_report=certification,
        response_envelope=envelope,
        assurance_bundle=assurance,
        signing_secret=signing_secret,
    )

    case.error_if(
        verify_integration_profile(
            profile,
            provider_card=provider_card,
            certification_report=certification,
            response_envelope=envelope,
            assurance_bundle=assurance,
            signing_secret=signing_secret,
        ),
        "integration_profile_errors",
    )
    case.check(
        "profile_ready_for_api_integration",
        profile["summary"]["status"] == "ready"
        and profile["summary"]["offline_verification_supported"]
        and profile["summary"]["endpoint_count"] >= 6
        and profile["summary"]["schema_count"] >= 14,
        profile["summary"],
    )
    case.check(
        "profile_requires_response_envelope_and_l21",
        profile["api_contract"]["required_response_format"]
        == "rdllm-response-envelope/v1"
        and profile["verifier_contract"]["minimum_certification_level"] == "RDLLM-L21"
        and profile["readiness_checks"]["certification_level_at_least_l21"],
        profile["verifier_contract"],
    )
    case.check(
        "profile_binds_public_proof_hashes",
        profile["bound_artifacts"]["provider_card_hash"] == provider_card["card_hash"]
        and profile["bound_artifacts"]["certification_report_hash"]
        == certification["report_hash"]
        and profile["bound_artifacts"]["response_envelope_hash"]
        == envelope["envelope_hash"]
        and profile["bound_artifacts"]["assurance_bundle_hash"]
        == assurance["bundle_hash"],
        profile["bound_artifacts"],
    )
    case.check(
        "profile_declares_required_surfaces_and_schemas",
        all(profile["public_surfaces"].values())
        and "response_envelope" in profile["schemas"]
        and "integration_profile" in profile["schemas"],
        {
            "public_surfaces": profile["public_surfaces"],
            "schemas": profile["schemas"],
        },
    )
    case.check(
        "profile_tampering_rejected",
        any("hash is not reproducible" in error for error in tampered_profile_errors)
        or any("api_contract does not match" in error for error in tampered_profile_errors),
        tampered_profile_errors,
    )
    case.check(
        "certification_regression_rejected",
        any("certification" in error for error in lower_profile_errors)
        or any("readiness" in error for error in lower_profile_errors),
        lower_profile_errors,
    )
    case.check(
        "provider_surface_drift_rejected",
        any("public_surfaces" in error for error in missing_surface_errors)
        or any("readiness" in error for error in missing_surface_errors),
        missing_surface_errors,
    )
    case.artifact("profile_hash", profile["profile_hash"])
    case.artifact("endpoint_count", profile["summary"]["endpoint_count"])
    case.artifact("schema_count", profile["summary"]["schema_count"])
    case.artifact("response_envelope_hash", envelope["envelope_hash"])
    return case.report()


