def _post_publication_rights_remediation_case(
    *,
    signing_secret: str | None,
) -> dict[str, Any]:
    case = CaseBuilder(
        "post_publication_rights_remediation",
        "Consent and revocation changes produce a signed remediation report that preserves historical event hashes and blocks future use.",
    )
    creator = Creator(
        "creator_revocable",
        "Revocable Rights Owner",
        "acct_revocable",
    )
    previous_work = Work(
        "revocable-rights-source",
        creator.creator_id,
        "Revocable Rights Source",
        "Revocable source text proves that creators can revoke future AI uses while historical royalty events remain preserved.",
        source_uri="https://example.test/rights/revocable-source",
        license="royalty-bearing",
        policy_id="policy:revocable-rights-source",
        allowed_uses=(
            "training",
            "retrieval",
            "generation",
            "display",
            "quote",
            "external_attribution",
        ),
    )
    updated_work = Work(
        previous_work.work_id,
        previous_work.creator_id,
        previous_work.title,
        previous_work.content,
        source_uri=previous_work.source_uri,
        license="revoked-rights-reserved",
        policy_id=previous_work.policy_id,
        allowed_uses=(),
        prohibited_uses=(
            "training",
            "retrieval",
            "generation",
            "display",
            "quote",
            "external_attribution",
        ),
        revoked=True,
        revoked_at="2026-05-30T00:00:00Z",
    )
    previous_engine = RoyaltyDrivenLLM([creator], [previous_work])
    updated_engine = RoyaltyDrivenLLM([creator], [updated_work])
    historical_event = previous_engine.attribute_text(
        "Historical attribution before revocation",
        previous_work.content,
        gross_revenue=Decimal("1.00"),
    )
    ledger = RoyaltyLedger()
    ledger.record(historical_event)
    report = make_rights_remediation_report(
        previous_engine,
        updated_engine,
        ledger.to_dict(),
        gross_revenue=Decimal("1.00"),
        creator_pool_rate=Decimal("0.55"),
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    verification_errors = verify_rights_remediation_report(
        report,
        previous_engine,
        updated_engine,
        ledger.to_dict(),
        signing_secret=signing_secret,
    )
    tampered = deepcopy(report)
    tampered["enforcement_probes"] = deepcopy(tampered["enforcement_probes"])
    tampered["enforcement_probes"][0]["future_use_denied"] = False
    tampered_errors = verify_rights_remediation_report(
        tampered,
        previous_engine,
        updated_engine,
        ledger.to_dict(),
        signing_secret=signing_secret,
    )
    report_text = canonical_json(report)
    private_leaks = [
        value
        for value in (
            previous_work.content,
            historical_event.prompt,
            historical_event.output,
            historical_event.answer_text,
        )
        if len(value) >= 16 and value in report_text
    ]

    blocked_probe = report["enforcement_probes"][0]["blocked_output_probe"]
    case.error_if(previous_engine.audit_event(historical_event), "historical_event_errors")
    case.error_if(verification_errors, "rights_remediation_errors")
    case.check(
        "remediation_report_ready",
        report["summary"]["status"] == "ready"
        and report["summary"]["changed_work_count"] == 1
        and report["summary"]["revoked_work_count"] == 1
        and report["summary"]["future_denial_count"] >= 6,
        report["summary"],
    )
    case.check(
        "historical_event_hash_preserved",
        report["historical_event_refs"][0]["event_hash"] == historical_event.event_hash
        and report["summary"]["historical_events_preserved"] is True,
        report["historical_event_refs"],
    )
    case.check(
        "future_use_denied_and_escrow_verified",
        blocked_probe is not None
        and blocked_probe["rights_conflict_escrow_verified"] is True
        and report["summary"]["rights_conflict_escrow_verified"] is True,
        blocked_probe,
    )
    case.check(
        "revoked_source_not_retrievable",
        report["enforcement_probes"][0]["retrieval_probe"][
            "retrieval_policy_enforced"
        ]
        is True,
        report["enforcement_probes"][0]["retrieval_probe"],
    )
    case.check(
        "remediation_report_redacts_private_text",
        not private_leaks
        and report["privacy"]["work_text_disclosed"] is False
        and report["privacy"]["private_ledger_disclosed"] is False,
        private_leaks[:3],
    )
    case.check(
        "remediation_tampering_rejected",
        any("hash" in error or "replay" in error for error in tampered_errors),
        tampered_errors,
    )
    case.artifact("rights_remediation_report_hash", report["report_hash"])
    case.artifact("changed_work_count", report["summary"]["changed_work_count"])
    case.artifact("future_denial_count", report["summary"]["future_denial_count"])
    case.artifact("historical_event_count", report["summary"]["historical_event_count"])
    return case.report()


def _semantic_text_attribution_case(*, signing_secret: str | None) -> dict[str, Any]:
    case = CaseBuilder(
        "semantic_text_attribution",
        "Semantic text attribution ranks paraphrased outputs, emits source footers, and escrows ambiguous text.",
    )
    creators = [
        Creator("creator_rights", "Rights Framework Author", "acct_rights"),
        Creator("creator_decoy", "Generic Marketplace Author", "acct_decoy"),
    ]
    source = Work(
        "creator-rights-market",
        "creator_rights",
        "Creator Rights Market",
        (
            "A creator-rights marketplace lets authors approve AI use, set licensing "
            "conditions, contest duplicate ownership claims, and appeal attribution "
            "mistakes before royalties are released."
        ),
        source_uri="https://example.test/creator-rights-market",
    )
    decoy = Work(
        "generic-market-dashboard",
        "creator_decoy",
        "Generic Market Dashboard",
        (
            "A generic market dashboard lists orders, refund windows, search filters, "
            "and account preferences for ordinary commerce operations."
        ),
        source_uri="https://example.test/generic-market-dashboard",
    )
    engine = RoyaltyDrivenLLM(creators, [source, decoy], top_k=2)
    semantic_inputs = [
        {
            "input_id": "paraphrased_creator_rights",
            "prompt": "How should creators control AI reuse?",
            "output": (
                "The system should let artists authorize model use, choose license "
                "terms, dispute duplicate owner claims, and ask for review when credit "
                "or royalty allocation is wrong."
            ),
        },
        {
            "input_id": "unmatched_science_note",
            "prompt": "What did the lab observe?",
            "output": (
                "Spectral readings from a telescope array indicated a cold methane "
                "plume above a distant moon."
            ),
        },
    ]
    report = make_semantic_text_attribution_report(
        engine,
        semantic_inputs,
        gross_revenue=Decimal("1.00"),
        creator_pool_rate=Decimal("0.55"),
        accept_threshold=0.20,
        min_margin=0.02,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    verification_errors = verify_semantic_text_attribution_report(
        report,
        engine,
        semantic_inputs,
        signing_secret=signing_secret,
    )
    tampered = deepcopy(report)
    tampered["source_footers"] = deepcopy(tampered["source_footers"])
    tampered["source_footers"][0]["footer_text_hash"] = "0" * 64
    tampered_errors = verify_semantic_text_attribution_report(
        tampered,
        engine,
        semantic_inputs,
        signing_secret=signing_secret,
    )
    report_text = canonical_json(report)
    private_leaks = [
        value
        for value in (
            source.content,
            decoy.content,
            semantic_inputs[0]["prompt"],
            semantic_inputs[0]["output"],
            semantic_inputs[1]["output"],
        )
        if len(value) >= 16 and value in report_text
    ]
    accepted_share = next(
        share for share in report["royalty_shares"] if share["input_id"] == "paraphrased_creator_rights"
    )
    escrow_share = next(
        share for share in report["royalty_shares"] if share["input_id"] == "unmatched_science_note"
    )
    accepted_footer = next(
        footer for footer in report["source_footers"] if footer["input_id"] == "paraphrased_creator_rights"
    )

    case.error_if(verification_errors, "semantic_text_attribution_errors")
    case.check(
        "semantic_report_ready_and_conserves_pool",
        report["summary"]["status"] == "ready"
        and report["summary"]["semantic_text_attribution"] is True
        and report["summary"]["creator_pool_conserved"] is True,
        report["summary"],
    )
    case.check(
        "paraphrase_attributed_to_expected_owner",
        accepted_share["decision"] == "accepted"
        and accepted_share["creator_id"] == "creator_rights"
        and accepted_share["work_id"] == "creator-rights-market",
        accepted_share,
    )
    case.check(
        "hard_decoy_not_paid",
        all(
            share["creator_id"] != "creator_decoy"
            for share in report["royalty_shares"]
        ),
        report["royalty_shares"],
    )
    case.check(
        "unmatched_text_routes_to_semantic_escrow",
        escrow_share["creator_id"] == "semantic_text_escrow"
        and escrow_share["decision"] == "semantic_text_escrow",
        escrow_share,
    )
    case.check(
        "source_footer_is_public_and_bound",
        accepted_footer["footer_status"] == "attributed"
        and accepted_footer["sources"][0]["label"] == "S1"
        and accepted_footer["sources"][0]["work_id"] == "creator-rights-market"
        and accepted_footer["footer_text_hash"],
        accepted_footer,
    )
    case.check(
        "semantic_report_redacts_private_text",
        not private_leaks
        and report["privacy"]["source_text_disclosed"] is False
        and report["privacy"]["output_text_disclosed"] is False,
        private_leaks[:3],
    )
    case.check(
        "semantic_footer_tampering_rejected",
        any("hash" in error or "replay" in error for error in tampered_errors),
        tampered_errors,
    )
    case.artifact("semantic_text_report_hash", report["report_hash"])
    case.artifact("accepted_input_count", report["summary"]["accepted_input_count"])
    case.artifact("escrow_input_count", report["summary"]["escrow_input_count"])
    case.artifact("source_footer_count", report["summary"]["source_footer_count"])
    return case.report()


