    certification_report: dict[str, Any] = {
        "certification_version": CERTIFICATION_VERSION,
        "suite": CERTIFICATION_SUITE,
        "issued_at": CERTIFICATION_ISSUED_AT,
        "summary": {
            "status": "passed",
            "case_count": 34,
            "passed": 34,
            "failed": 0,
            "score": 1.0,
            "highest_level": "RDLLM-L33",
        },
        "levels": {},
        "cases": [],
    }
    certification_report["report_hash"] = hash_payload(certification_report)
    provider_card = make_provider_attribution_card(
        ledger.to_dict(),
        certification_report=certification_report,
        issuer="rdllm-certifier",
        provider="provider:rdllm-certifier",
        model_id="model:rdllm-reference",
        model_version="2026-05",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    envelope = make_response_envelope(
        event,
        answer_card=answer_card,
        source_verification_report=source_report,
        public_receipt=public_receipt(receipt),
        provider_card=provider_card,
        certification_report=certification_report,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    profile = make_integration_profile(
        provider_card=provider_card,
        certification_report=certification_report,
        response_envelope=envelope,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    semantic_inputs = [
        {
            "input_id": "external_provenance_answer",
            "prompt": "How should provenance answers be sourced?",
            "output": TEXT_ATTRIBUTION_OUTPUT,
        },
        {
            "input_id": "unmatched_weather_note",
            "prompt": "What did the local report say?",
            "output": "A late storm moved over the harbor after sunset.",
        },
    ]
    semantic_report = make_semantic_text_attribution_report(
        engine,
        semantic_inputs,
        gross_revenue=Decimal("1.00"),
        creator_pool_rate=Decimal("0.55"),
        accept_threshold=0.20,
        min_margin=0.02,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    license_contract = _case_creator_license_contract(
        engine,
        signing_secret=signing_secret,
    )
    assurance = make_assurance_bundle(
        [
            ("certification", "certification_report", certification_report),
            ("integration_profile", "integration_profile", profile),
            ("response_envelope", "response_envelope", envelope),
            ("answer_card", "answer_provenance_card", answer_card),
            ("source_verification", "source_verification_report", source_report),
            ("provider_card", "provider_attribution_card", provider_card),
            ("semantic_text", "semantic_text_attribution_report", semantic_report),
            ("creator_license_contract", "creator_license_contract", license_contract),
            ("receipt", "attribution_receipt", receipt),
            ("trace", "trace_exchange", trace),
        ],
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    discovery = make_discovery_manifest(
        provider_card=provider_card,
        certification_report=certification_report,
        integration_profile=profile,
        response_envelope=envelope,
        assurance_bundle=assurance,
        semantic_text_attribution_report=semantic_report,
        creator_license_contract=license_contract,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    exchange = make_attribution_exchange_manifest(
        provider_card=provider_card,
        certification_report=certification_report,
        integration_profile=profile,
        discovery_manifest=discovery,
        response_envelope=envelope,
        assurance_bundle=assurance,
        semantic_text_attribution_report=semantic_report,
        creator_license_contract=license_contract,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    vector_pack = make_conformance_vector_pack(
        provider_card=provider_card,
        certification_report=certification_report,
        integration_profile=profile,
        discovery_manifest=discovery,
        response_envelope=envelope,
        assurance_bundle=assurance,
        semantic_text_attribution_report=semantic_report,
        creator_license_contract=license_contract,
        attribution_exchange=exchange,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    handshake = make_federation_handshake(
        provider_card=provider_card,
        certification_report=certification_report,
        integration_profile=profile,
        discovery_manifest=discovery,
        response_envelope=envelope,
        assurance_bundle=assurance,
        semantic_text_attribution_report=semantic_report,
        creator_license_contract=license_contract,
        attribution_exchange=exchange,
        conformance_vector_pack=vector_pack,
        requester="provider:downstream",
        requester_model_id="model:downstream",
        requester_model_version="2026-05",
        minimum_certification_level="RDLLM-L33",
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    capsule = make_attribution_capsule(
        response_envelope=envelope,
        federation_handshake=handshake,
        attribution_exchange=exchange,
        conformance_vector_pack=vector_pack,
        provider_card=provider_card,
        certification_report=certification_report,
        integration_profile=profile,
        discovery_manifest=discovery,
        assurance_bundle=assurance,
        semantic_text_attribution_report=semantic_report,
        creator_license_contract=license_contract,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    copied_output = (
        f"{envelope['response']['rendered_output']}\n\n"
        f"{capsule['portable_surfaces']['text_footer']}"
    )
    verification_errors = verify_attribution_capsule(
        capsule,
        response_envelope=envelope,
        federation_handshake=handshake,
        attribution_exchange=exchange,
        conformance_vector_pack=vector_pack,
        provider_card=provider_card,
        certification_report=certification_report,
        integration_profile=profile,
        discovery_manifest=discovery,
        assurance_bundle=assurance,
        semantic_text_attribution_report=semantic_report,
        creator_license_contract=license_contract,
        copied_output=copied_output,
        signing_secret=signing_secret,
    )
    tampered = deepcopy(capsule)
    tampered["subject"] = dict(tampered["subject"])
    tampered["subject"]["rendered_output_hash"] = "0" * 64
    tampered_errors = verify_attribution_capsule(
        tampered,
        response_envelope=envelope,
        federation_handshake=handshake,
        attribution_exchange=exchange,
        conformance_vector_pack=vector_pack,
        provider_card=provider_card,
        certification_report=certification_report,
        integration_profile=profile,
        discovery_manifest=discovery,
        assurance_bundle=assurance,
        semantic_text_attribution_report=semantic_report,
        creator_license_contract=license_contract,
        signing_secret=signing_secret,
    )
    missing_marker_errors = verify_attribution_capsule(
        capsule,
        response_envelope=envelope,
        federation_handshake=handshake,
        attribution_exchange=exchange,
        conformance_vector_pack=vector_pack,
        provider_card=provider_card,
        certification_report=certification_report,
        integration_profile=profile,
        discovery_manifest=discovery,
        assurance_bundle=assurance,
        semantic_text_attribution_report=semantic_report,
        creator_license_contract=license_contract,
        copied_output=envelope["response"]["rendered_output"],
        signing_secret=signing_secret,
    )
    tampered_copy_errors = verify_attribution_capsule(
        capsule,
        response_envelope=envelope,
        federation_handshake=handshake,
        attribution_exchange=exchange,
        conformance_vector_pack=vector_pack,
        provider_card=provider_card,
        certification_report=certification_report,
        integration_profile=profile,
        discovery_manifest=discovery,
        assurance_bundle=assurance,
        semantic_text_attribution_report=semantic_report,
        creator_license_contract=license_contract,
        copied_output=copied_output.replace(
            "Royalty-aware answer:", "Altered answer:", 1
        ),
        signing_secret=signing_secret,
    )
    capsule_text = canonical_json(capsule)
    private_leaks = [
        value
        for value in (
            event.prompt,
            event.output,
            semantic_inputs[0]["prompt"],
            semantic_inputs[0]["output"],
            semantic_inputs[1]["output"],
        )
        if len(value) >= 16 and value in capsule_text
    ]

    case.error_if(verification_errors, "attribution_capsule_errors")
    case.check(
        "capsule_ready_and_copyable",
        capsule["summary"]["status"] == "ready"
        and capsule["summary"]["target_certification_level"] == "RDLLM-L34"
        and capsule["summary"]["minimum_upstream_level"] == "RDLLM-L33"
        and capsule["summary"]["copyable"] is True,
        capsule["summary"],
    )
    case.check(
        "copy_marker_and_runtime_headers_declared",
        capsule["summary"]["capsule_id"] in capsule["portable_surfaces"]["text_footer"]
        and capsule["portable_surfaces"]["delivery_contract"]["body_hash"]
        == capsule["subject"]["rendered_output_hash"]
        and {
            "RDLLM-Capsule-ID",
            "RDLLM-Capsule-Hash",
            "RDLLM-Output-Hash",
            "RDLLM-Handshake-Hash",
            "RDLLM-Signature",
        }.issubset(set(capsule["portable_surfaces"]["http_headers"])),
        capsule["portable_surfaces"],
    )
    case.check(
        "c2pa_and_scitt_surfaces_declared",
        capsule["portable_surfaces"]["c2pa_assertion"][
            "not_a_tdm_rights_assertion"
        ]
        is True
        and capsule["portable_surfaces"]["scitt_statement_subject"]["digest"]["sha256"]
        == capsule["subject"]["rendered_output_hash"],
        capsule["portable_surfaces"],
    )
    case.check(
        "copied_output_marker_verified",
        not missing_marker_errors
        or any("missing attribution capsule marker" in error for error in missing_marker_errors),
        missing_marker_errors,
    )
    case.check(
        "copied_output_body_tampering_rejected",
        any("body hash" in error for error in tampered_copy_errors),
        tampered_copy_errors,
    )
    case.check(
        "capsule_redacts_private_text",
        not private_leaks
        and capsule["privacy"]["prompt_text_disclosed"] is False
        and capsule["privacy"]["source_text_disclosed"] is False
        and capsule["privacy"]["hidden_state_disclosed"] is False,
        private_leaks[:3],
    )
    case.check(
        "capsule_tampering_rejected",
        any("hash" in error or "subject" in error for error in tampered_errors),
        tampered_errors,
    )
    case.artifact("capsule_hash", capsule["capsule_hash"])
    case.artifact("capsule_id", capsule["summary"]["capsule_id"])
    case.artifact("artifact_count", capsule["summary"]["artifact_count"])
    return case.report()


