def _independent_verifier_quorum_case(
    *,
    signing_secret: str | None,
) -> dict[str, Any]:
    case = CaseBuilder(
        "independent_verifier_quorum",
        "Direct settlement after attribution consensus requires multiple independent signed replay attestations, with disagreement routed to verifier escrow.",
    )

    def hashed(field: str, payload: dict[str, Any]) -> dict[str, Any]:
        artifact = deepcopy(payload)
        artifact[field] = hash_payload(artifact)
        return artifact

    attribution_consensus_report = hashed(
        "report_hash",
        {
            "report_version": "rdllm-attribution-consensus-report/v1",
            "summary": {
                "status": "ready",
                "target_certification_level": "RDLLM-L70",
            },
            "checks": {
                "creator_pool_conserved": True,
            },
            "economics": {
                "creator_pool": "0.550000",
                "payout_total": "0.550000",
                "escrow_total": "0.000000",
            },
            "royalty_shares": [
                {
                    "creator_id": "creator_consensus",
                    "work_id": "work_consensus_support",
                    "decision": "accepted",
                    "payout": "0.550000",
                    "contribution_weight": 1.0,
                }
            ],
        },
    )
    provider_card = hashed(
        "card_hash",
        {
            "card_version": "rdllm-provider-attribution-card/v1",
            "public_disclosure_surfaces": {
                "attribution_consensus_report": True,
                "verifier_quorum_report": True,
            },
            "supported_evidence_channels": {
                "attribution_consensus": True,
                "independent_verifier_quorum": True,
            },
        },
    )
    certification_report = hashed(
        "report_hash",
        {
            "certification_version": CERTIFICATION_VERSION,
            "suite": CERTIFICATION_SUITE,
            "issued_at": CERTIFICATION_ISSUED_AT,
            "summary": {
                "status": "passed",
                "case_count": 71,
                "passed": 71,
                "failed": 0,
                "score": 1.0,
                "highest_level": "RDLLM-L70",
            },
            "levels": {},
            "cases": [],
        },
    )
    integration_profile = hashed(
        "profile_hash",
        {
            "profile_version": "rdllm-integration-profile/v1",
            "summary": {"status": "ready"},
            "schemas": {
                "verifier_quorum_report": "docs/schemas/verifier_quorum_report.schema.json",
            },
            "public_surfaces": {"verifier_quorum_report": True},
        },
    )
    verifier_secrets = {
        "verifier_alpha": "secret-alpha",
        "verifier_beta": "secret-beta",
        "verifier_gamma": "secret-gamma",
    }
    report = make_verifier_quorum_report(
        attribution_consensus_report=attribution_consensus_report,
        provider_card=provider_card,
        certification_report=certification_report,
        integration_profile=integration_profile,
        verifier_secrets=verifier_secrets,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    verification_errors = verify_verifier_quorum_report(
        report,
        attribution_consensus_report=attribution_consensus_report,
        provider_card=provider_card,
        certification_report=certification_report,
        integration_profile=integration_profile,
        verifier_secrets=verifier_secrets,
        signing_secret=signing_secret,
    )
    tampered = deepcopy(report)
    tampered["verifier_rows"] = deepcopy(tampered["verifier_rows"])
    tampered["verifier_rows"][0] = dict(tampered["verifier_rows"][0])
    tampered["verifier_rows"][0]["signature"] = "0" * 64
    tampered_errors = verify_verifier_quorum_report(
        tampered,
        attribution_consensus_report=attribution_consensus_report,
        provider_card=provider_card,
        certification_report=certification_report,
        integration_profile=integration_profile,
        verifier_secrets=verifier_secrets,
        signing_secret=signing_secret,
    )
    disputed_report = make_verifier_quorum_report(
        attribution_consensus_report=attribution_consensus_report,
        provider_card=provider_card,
        certification_report=certification_report,
        integration_profile=integration_profile,
        verifier_specs=[
            {
                "verifier_id": "verifier_alpha",
                "organization_id": "org:alpha",
                "replay_verdict": "accepted",
            },
            {
                "verifier_id": "verifier_beta",
                "organization_id": "org:beta",
                "replay_verdict": "accepted",
            },
            {
                "verifier_id": "verifier_gamma",
                "organization_id": "org:gamma",
                "replay_verdict": "disputed",
            },
        ],
        verifier_secrets=verifier_secrets,
        minimum_quorum=2,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    disputed_errors = verify_verifier_quorum_report(
        disputed_report,
        attribution_consensus_report=attribution_consensus_report,
        provider_card=provider_card,
        certification_report=certification_report,
        integration_profile=integration_profile,
        verifier_secrets=verifier_secrets,
        signing_secret=signing_secret,
    )

    case.error_if(verification_errors, "verifier_quorum_errors")
    case.error_if(disputed_errors, "verifier_quorum_disputed_errors")
    case.check(
        "verifier_quorum_report_committed_l71",
        report["summary"]["status"] == "ready"
        and report["summary"]["target_certification_level"] == "RDLLM-L71"
        and report["summary"]["accepted_verifier_count"] == 3
        and report["summary"]["direct_settlement_ready"] is True,
        report["summary"],
    )
    case.check(
        "independent_verifier_signatures_gate_direct_settlement",
        report["checks"]["verifier_signatures_valid"]
        and report["checks"]["accepted_verifier_quorum_met"]
        and report["checks"]["independent_organization_quorum_met"]
        and report["settlement_gate"]["decision"] == "direct_settlement_ready",
        report["settlement_gate"],
    )
    case.check(
        "disagreement_routes_to_verifier_escrow",
        disputed_report["summary"]["status"] == "escrow"
        and disputed_report["settlement_gate"]["decision"] == "verifier_quorum_escrow"
        and disputed_report["checks"]["no_rejecting_or_disputing_verifiers"] is False
        and all(
            row["settlement_decision"] == "verifier_quorum_escrow"
            for row in disputed_report["settlement_rows"]
        ),
        disputed_report["settlement_gate"],
    )
    case.check(
        "verifier_quorum_pool_conserved_and_private_text_redacted",
        report["checks"]["creator_pool_conserved_or_escrowed"]
        and report["checks"]["public_report_has_no_private_field_names"]
        and report["privacy"]["private_prompt_disclosed"] is False
        and report["privacy"]["private_source_text_disclosed"] is False,
        report["privacy"],
    )
    case.check(
        "verifier_signature_tampering_rejected",
        any("hash" in error or "signature" in error for error in tampered_errors),
        tampered_errors,
    )
    case.artifact("verifier_quorum_report_hash", report["report_hash"])
    case.artifact(
        "verifier_attestation_root",
        report["commitments"]["verifier_attestation_root"],
    )
    case.artifact("accepted_verifier_count", report["summary"]["accepted_verifier_count"])
    return case.report()


