    hidden_label_input = deepcopy(reasoning_input)
    hidden_label_input["reasoning_steps"][0]["visible_source_labels"] = []
    hidden_label = make_private_reasoning_attribution_receipt(
        hidden_label_input,
        issued_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    missing_commitment_input = deepcopy(reasoning_input)
    missing_commitment_input["reasoning_steps"][0].pop("private_trace_text", None)
    missing_commitment_input["reasoning_steps"][0].pop("private_trace_hash", None)
    missing_commitment_input["reasoning_steps"][0].pop("private_trace_salt", None)
    missing_commitment = make_private_reasoning_attribution_receipt(
        missing_commitment_input,
        issued_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    missing_memory_artifact_input = deepcopy(reasoning_input)
    missing_memory_artifact_input["reasoning_steps"][0]["input_artifact_hashes"] = [
        client_receipt["client_enforcement_hash"]
    ]
    missing_memory_artifact = make_private_reasoning_attribution_receipt(
        missing_memory_artifact_input,
        issued_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    missing_delegate_model_input = deepcopy(reasoning_input)
    missing_delegate_model_input["reasoning_steps"][1]["delegate_model_id"] = ""
    missing_delegate_model = make_private_reasoning_attribution_receipt(
        missing_delegate_model_input,
        issued_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    tampered = deepcopy(receipt)
    tampered["reasoning_steps"][0] = dict(tampered["reasoning_steps"][0])
    tampered["reasoning_steps"][0]["visible_source_labels"] = []
    tampered_errors = verify_private_reasoning_attribution_receipt(
        tampered,
        reasoning_input,
        signing_secret=signing_secret,
    )

    case.error_if(verification_errors, "private_reasoning_attribution_errors")
    case.check(
        "private_reasoning_attribution_ready_l107",
        receipt["summary"]["status"] == "ready"
        and receipt["summary"]["target_certification_level"] == "RDLLM-L107",
        receipt["summary"],
    )
    case.check(
        "private_reasoning_commits_hidden_trace_without_disclosure",
        receipt["checks"]["reasoning_steps_have_private_commitments"]
        and receipt["checks"]["raw_private_reasoning_not_disclosed"]
        and receipt["summary"]["privacy_preserved"] is True,
        receipt["checks"],
    )
    case.check(
        "hidden_reasoning_source_labels_must_reach_footer",
        receipt["checks"]["reasoning_source_labels_visible_in_footer"]
        and receipt["checks"]["reasoning_royalty_obligations_cover_sources"],
        receipt["checks"],
    )
    case.check(
        "private_reasoning_binds_l106_memory_and_client_output",
        receipt["checks"]["persistent_memory_provenance_verified"]
        and receipt["checks"]["memory_reasoning_steps_bind_l106_receipt"]
        and receipt["checks"]["reasoning_steps_bind_client_rendered_output"],
        receipt["checks"],
    )
    case.check(
        "hidden_private_reasoning_label_blocks_direct_use",
        hidden_label["summary"]["status"] == "blocked"
        and not hidden_label["checks"]["reasoning_source_labels_visible_in_footer"],
        hidden_label["checks"],
    )
    case.check(
        "missing_private_reasoning_commitment_blocks_direct_use",
        missing_commitment["summary"]["status"] == "blocked"
        and not missing_commitment["checks"][
            "reasoning_steps_have_private_commitments"
        ],
        missing_commitment["checks"],
    )
    case.check(
        "missing_l106_memory_artifact_blocks_memory_reasoning",
        missing_memory_artifact["summary"]["status"] == "blocked"
        and not missing_memory_artifact["checks"][
            "memory_reasoning_steps_bind_l106_receipt"
        ],
        missing_memory_artifact["checks"],
    )
    case.check(
        "delegation_without_model_identity_blocks_direct_use",
        missing_delegate_model["summary"]["status"] == "blocked"
        and not missing_delegate_model["checks"][
            "delegation_steps_identify_model_and_artifacts"
        ],
        missing_delegate_model["checks"],
    )
    case.check(
        "private_reasoning_redacts_private_text",
        event.prompt not in canonical_json(receipt)
        and event.answer_text not in canonical_json(receipt)
        and private_reasoning_text not in canonical_json(receipt)
        and delegate_reasoning_text not in canonical_json(receipt),
        receipt["privacy"],
    )
    case.check(
        "private_reasoning_tampering_rejected",
        any("mismatch" in error for error in tampered_errors),
        tampered_errors,
    )
    case.artifact(
        "private_reasoning_attribution_hash",
        receipt["private_reasoning_attribution_hash"],
    )
    case.artifact("reasoning_step_count", receipt["summary"]["reasoning_step_count"])
    return case.report()


