    counterevidence = make_counterevidence_report(
        event,
        engine,
        answer_card=answer_card,
        source_verification_report=source_report,
        source_availability_report=source_availability,
        evidence_sufficiency_report=evidence_sufficiency,
        citation_footer_contract=citation_footer,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    answer_coverage = make_answer_claim_coverage_report(
        rendered_output=event.output,
        event_id=event.event_id,
        event_hash=event.event_hash,
        answer_hash=stable_hash(event.answer_text or event.output),
        answer_card=answer_card,
        source_verification_report=source_report,
        evidence_sufficiency_report=evidence_sufficiency,
        counterevidence_report=counterevidence,
        citation_footer_contract=citation_footer,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    closed_envelope = make_response_envelope(
        event,
        answer_card=answer_card,
        source_verification_report=source_report,
        source_confidence_report=source_confidence,
        creator_license_contract=license_contract,
        citation_footer_contract=citation_footer,
        source_availability_report=source_availability,
        evidence_sufficiency_report=evidence_sufficiency,
        counterevidence_report=counterevidence,
        answer_claim_coverage_report=answer_coverage,
        public_receipt=public_receipt(receipt),
        provider_card=provider_card,
        certification_report=certification,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )

    capsule_footer = "RDLLM attribution capsule: rdllm-cap-answer-coverage"
    capsule = {
        "capsule_version": "rdllm-attribution-capsule/v1",
        "issuer": "rdllm-certifier",
        "created_at": CERTIFICATION_ISSUED_AT,
        "provider": {
            "id": "provider:rdllm-certifier",
            "model_id": "model:rdllm-certifier",
            "model_version": "2026-05",
        },
        "subject": {
            "content_kind": "text",
            "event_id": event.event_id,
            "event_hash": event.event_hash,
            "rendered_output_hash": closed_envelope["response"]["rendered_output_hash"],
            "answer_hash": closed_envelope["response"]["answer_hash"],
            "source_label_root": closed_envelope["commitments"]["footer_label_root"],
            "claim_span_root": closed_envelope["commitments"]["footer_span_root"],
            "source_count": closed_envelope["summary"]["source_count"],
            "claim_count": closed_envelope["summary"]["claim_count"],
        },
        "portable_surfaces": {
            "capsule_id": "rdllm-cap-answer-coverage",
            "text_footer": capsule_footer,
            "markdown_comment": f"<!-- {capsule_footer} -->",
            "http_headers": {},
            "well_known_path": "/.well-known/rdllm/attribution-capsule.json",
            "c2pa_assertion": {},
            "scitt_statement_subject": {},
            "delivery_contract": {
                "contract_version": "rdllm-delivered-output/v1",
                "body_hash": closed_envelope["response"]["rendered_output_hash"],
                "footer_marker_hash": stable_hash(capsule_footer),
            },
        },
        "artifact_bindings": [
            {"name": name}
            for name in (
                "response_envelope",
                "federation_handshake",
                "attribution_exchange",
                "conformance_vector_pack",
                "provider_attribution_card",
                "certification_report",
                "integration_profile",
                "discovery_manifest",
                "assurance_bundle",
                "semantic_text_attribution_report",
                "creator_license_contract",
            )
        ],
        "schemas": {"attribution_capsule": "docs/schemas/attribution_capsule.schema.json"},
        "commitments": {},
        "readiness_checks": {},
        "summary": {"status": "ready", "target_certification_level": "RDLLM-L34"},
        "privacy": {},
        "capsule_hash": stable_hash("answer-coverage-capsule"),
        "signature": {"algorithm": "UNSIGNED", "issuer": "rdllm-certifier", "value": ""},
    }
    capsule["portable_surfaces"]["http_headers"]["RDLLM-Capsule-Hash"] = capsule[
        "capsule_hash"
    ]
    release_gate = make_release_gate_report(
        response_envelope=closed_envelope,
        attribution_capsule=capsule,
        creator_license_contract=license_contract,
        provider_card=provider_card,
        certification_report=certification,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    envelope_errors = verify_response_envelope(
        closed_envelope,
        signing_secret=signing_secret,
    )
    gate_errors = verify_release_gate_report(
        release_gate,
        response_envelope=closed_envelope,
        attribution_capsule=capsule,
        creator_license_contract=license_contract,
        provider_card=provider_card,
        certification_report=certification,
        signing_secret=signing_secret,
    )

    incomplete_envelope = make_response_envelope(
        event,
        answer_card=answer_card,
        source_verification_report=source_report,
        source_confidence_report=source_confidence,
        creator_license_contract=license_contract,
        citation_footer_contract=citation_footer,
        source_availability_report=source_availability,
        evidence_sufficiency_report=evidence_sufficiency,
        counterevidence_report=counterevidence,
        public_receipt=public_receipt(receipt),
        provider_card=provider_card,
        certification_report=certification,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    incomplete_errors = verify_response_envelope(
        incomplete_envelope,
        signing_secret=signing_secret,
    )
    incomplete_gate = make_release_gate_report(
        response_envelope=incomplete_envelope,
        attribution_capsule=capsule,
        creator_license_contract=license_contract,
        provider_card=provider_card,
        certification_report=certification,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    unsupported_output = (
        event.output
        + "\nA hidden unsupported statement was added after the citation footer."
    )
    unsupported_report = make_answer_claim_coverage_report(
        rendered_output=unsupported_output,
        event_id=event.event_id,
        event_hash=event.event_hash,
        answer_hash=stable_hash(event.answer_text or event.output),
        answer_card=answer_card,
        source_verification_report=source_report,
        evidence_sufficiency_report=evidence_sufficiency,
        counterevidence_report=counterevidence,
        citation_footer_contract=citation_footer,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )
    unsupported_errors = verify_answer_claim_coverage_report(
        answer_coverage,
        rendered_output=unsupported_output,
        event_id=event.event_id,
        event_hash=event.event_hash,
        answer_hash=stable_hash(event.answer_text or event.output),
        answer_card=answer_card,
        source_verification_report=source_report,
        evidence_sufficiency_report=evidence_sufficiency,
        counterevidence_report=counterevidence,
        citation_footer_contract=citation_footer,
        signing_secret=signing_secret,
    )
    tampered_envelope = deepcopy(closed_envelope)
    tampered_coverage = tampered_envelope["embedded_artifacts"][
        "answer_claim_coverage_report"
    ]
    tampered_coverage["summary"] = dict(tampered_coverage["summary"])
    tampered_coverage["summary"]["unsupported_unit_count"] = 1
    tampered_gate = make_release_gate_report(
        response_envelope=tampered_envelope,
        attribution_capsule=capsule,
        creator_license_contract=license_contract,
        provider_card=provider_card,
        certification_report=certification,
        issuer="rdllm-certifier",
        created_at=CERTIFICATION_ISSUED_AT,
        signing_secret=signing_secret,
    )

    checks = release_gate.get("checks", {})
    coverage_summary = answer_coverage.get("summary", {})
    case.error_if(envelope_errors, "closed_response_envelope_errors")
    case.error_if(gate_errors, "release_gate_errors")
    case.error_if(
        verify_answer_claim_coverage_report(
            answer_coverage,
            rendered_output=event.output,
            event_id=event.event_id,
            event_hash=event.event_hash,
            answer_hash=stable_hash(event.answer_text or event.output),
            answer_card=answer_card,
            source_verification_report=source_report,
            evidence_sufficiency_report=evidence_sufficiency,
            counterevidence_report=counterevidence,
            citation_footer_contract=citation_footer,
            signing_secret=signing_secret,
        ),
        "answer_claim_coverage_errors",
    )
    case.check(
        "answer_coverage_ready_l59",
        coverage_summary.get("status") == "verified"
        and coverage_summary.get("target_certification_level") == "RDLLM-L59"
        and coverage_summary.get("all_answer_claims_covered") is True
        and coverage_summary.get("unsupported_unit_count") == 0,
        coverage_summary,
    )
    case.check(
        "l59_response_envelope_and_gate_require_answer_coverage",
        closed_envelope.get("summary", {}).get("status") == "verified"
        and release_gate.get("summary", {}).get("decision") == "emit"
        and checks.get("answer_claim_coverage_release_verified") is True
        and incomplete_envelope.get("summary", {}).get("status") == "failed"
        and any(
            "answer coverage" in error
            or "public verification checks" in error
            for error in incomplete_errors
        )
        and incomplete_gate.get("summary", {}).get("decision") == "hold_for_revision"
        and incomplete_gate.get("checks", {}).get(
            "answer_claim_coverage_release_verified"
        )
        is False,
        {
            "release_checks": checks,
            "incomplete_errors": incomplete_errors,
            "incomplete_gate": incomplete_gate.get("checks", {}),
        },
    )
    case.check(
        "answer_coverage_detects_unsupported_sentence_after_footer",
        unsupported_report.get("summary", {}).get("status") == "failed"
        and unsupported_report.get("summary", {}).get("unsupported_unit_count", 0) > 0
        and any("answer coverage" in error for error in unsupported_errors),
        {
            "unsupported_summary": unsupported_report.get("summary", {}),
            "unsupported_errors": unsupported_errors,
        },
    )
    case.check(
        "release_gate_blocks_answer_coverage_summary_drift",
        tampered_gate.get("summary", {}).get("decision") == "hold_for_revision"
        and tampered_gate.get("checks", {}).get(
            "answer_claim_coverage_release_verified"
        )
        is False,
        tampered_gate.get("checks", {}),
    )
    coverage_json = canonical_json(answer_coverage)
    case.check(
        "answer_coverage_report_redacts_private_text",
        event.prompt not in coverage_json
        and event.answer_text not in coverage_json
        and all(claim.claim not in coverage_json for claim in event.claim_support)
        and all(chunk.text not in coverage_json for chunk in engine.chunks),
        [],
    )
    case.artifact("closed_response_envelope_hash", closed_envelope["envelope_hash"])
    case.artifact("release_gate_hash", release_gate["gate_hash"])
    case.artifact("answer_claim_coverage_report_hash", answer_coverage["report_hash"])
    return case.report()


